// vocab.js - pure lookups into the wire's `vocabularies` block (positions,
// outcomes, roles, liveness - schema/yard-snapshot.schema.json's top-level
// `vocabularies` property). Recognition VALUES stay owned server-side by
// schema/vocab/*.json (Law 7); this module never hardcodes a taxonomy of
// its own - it only reads the defs the CURRENT snapshot already carried
// (design rev 5 S5.4 item 2 / Law 6: vocabularies travel on every snapshot
// so the view never fetches or hardcodes a separate copy that could drift).
//
// An id with no matching def is UNRECOGNISED - the discovery rule (design
// rev 5 S5.2, mockup brief "the discovery state") renders it hot, BY NAME,
// verbatim, never silently as calm.

/**
 * @param {Array<{id: string, label: string, register: string}>} defs
 * @param {string} id
 */
export function findVocabDef(defs, id) {
  if (!Array.isArray(defs)) return undefined;
  return defs.find((d) => d && d.id === id);
}

/**
 * Describe one vocabulary id against its defs array. Recognised ids get
 * their def's label + register; unrecognised ids render their raw id as
 * the label (verbatim) with register `needs-attention` (Law 1: unknown
 * must never look like "fine").
 *
 * @param {string} id
 * @param {Array<{id: string, label: string, register: string}>} defs
 */
export function describeVocab(id, defs) {
  const def = findVocabDef(defs, id);
  if (def) {
    return { id, label: def.label, register: def.register, recognised: true };
  }
  return { id, label: id, register: 'needs-attention', recognised: false };
}

{
  "$comment": "PRESENTATIONAL defs the wire schema's vocabularies block requires (schema/yard-snapshot.schema.json's top-level properties.vocabularies - positions/outcomes/roles/liveness arrays of {id, label, register}; C2R-1, review round 1: a line-number citation here rotted the instant a later commit in this same train (9d53b9c) inserted $defs above it, so this cites the section by its JSON-pointer path, not a line number that further edits can silently invalidate). Recognition VALUES stay owned by schema/vocab/outcomes.json and schema/vocab/roles.json (Law 7 - an unrecognised value is a detector discovery, never a validation failure) and by the mechanism-closed position (design rev 5 S5.2) and liveness (design rev 5 S5.6) sets; this file adds label+register presentation only, never a second recognition gate. THE REGISTER ASSIGNMENTS ARE PINNED (plan 2026-07-23-yard-board-plan.md task 2.4, so no car re-derives them): positions live/bagged/dark are nominal, under-construction is in-progress (design S5.2 table); liveness returned is nominal, dispatched is in-progress, overdue/presumed-lost are needs-attention (design S5.6 gradient); outcomes APPROVE/APPROVE-WITH-REBASE-LIST/REJECT/CONFIRM/done/honest-stop are nominal (REJECT and honest-stop are SUCCESS outcomes in this shop - the gates lane must not run hot on normal traffic), done-with-findings is in-progress, error is needs-attention; roles are all nominal. A value with no def renders by raw id through the detector path (schema/yard-snapshot.schema.json's properties.vocabularies description).",
  "positions": [
    { "id": "live", "label": "Live", "register": "nominal" },
    { "id": "bagged", "label": "Bagged", "register": "nominal" },
    { "id": "dark", "label": "Dark", "register": "nominal" },
    { "id": "under-construction", "label": "Under construction", "register": "in-progress" }
  ],
  "outcomes": [
    { "id": "APPROVE", "label": "Approve", "register": "nominal" },
    { "id": "APPROVE-WITH-REBASE-LIST", "label": "Approve (with rebase list)", "register": "nominal" },
    { "id": "REJECT", "label": "Reject", "register": "nominal" },
    { "id": "CONFIRM", "label": "Confirm", "register": "nominal" },
    { "id": "done", "label": "Done", "register": "nominal" },
    { "id": "honest-stop", "label": "Honest stop", "register": "nominal" },
    { "id": "done-with-findings", "label": "Done, with findings", "register": "in-progress" },
    { "id": "error", "label": "Error", "register": "needs-attention" }
  ],
  "roles": [
    { "id": "car", "label": "Car", "register": "nominal" },
    { "id": "reviewer", "label": "Reviewer", "register": "nominal" },
    { "id": "gate", "label": "Gate", "register": "nominal" }
  ],
  "liveness": [
    { "id": "returned", "label": "Returned", "register": "nominal" },
    { "id": "dispatched", "label": "Dispatched", "register": "in-progress" },
    { "id": "overdue", "label": "Overdue", "register": "needs-attention" },
    { "id": "presumed-lost", "label": "Presumed lost", "register": "needs-attention" }
  ]
}

