Select-String -Path docs/setup.md -Pattern 'trigger|defer|browser|visual|screenshot|playwright|e2e' -Context 0,1 | Select-Object -First 40 | ForEach-Object { "{0}: {1}" -f $_.LineNumber, $_.Line.Trim() }
Write-Host "`n=== repo-wide: any existing browser-test / playwright mention ==="
Select-String -Path (Get-ChildItem docs,board,scripts,.github -Recurse -Include *.md,*.yml,*.yaml,*.json -File | Select-Object -ExpandProperty FullName) -Pattern 'playwright|puppeteer|jsdom|happy-dom|headless' -ErrorAction SilentlyContinue | Select-Object -First 15 | ForEach-Object { "{0}:{1}: {2}" -f (Split-Path $_.Path -Leaf), $_.LineNumber, $_.Line.Trim() }

cd C:\Users\Chris\git\starcar
Write-Host "=== git status ==="; git status --porcelain
Write-Host "=== is .ci-checks tracked or ignored? ==="; git check-ignore -v .ci-checks/8a6cdb1d2.json 2>&1; git ls-files .ci-checks | Measure-Object | ForEach-Object { "tracked files in .ci-checks: $($_.Count)" }
Write-Host "`n=== BOARD AUDIT: open issues vs project 6 ==="
$board = gh project item-list 6 --owner polecatspeaks --format json --limit 100 --jq '[.items[]|select(.content.number!=null)|.content.number]|sort' | ConvertFrom-Json
$open  = gh issue list --state open --limit 100 --json number --jq '[.[].number]|sort' | ConvertFrom-Json
"on board : $($board.Count)"
"open     : $($open.Count)"
$missing = $open | Where-Object { $_ -notin $board }
if ($missing) { "MISSING FROM BOARD: $($missing -join ', ')" } else { "MISSING FROM BOARD: none - every open issue is visible" }

cd C:\Users\Chris\git\starcar
git log --oneline -2
Write-Host "`n=== did Car 33's dispatch record land? (#32 datapoint) ==="
Get-ChildItem artifacts -Recurse -Filter 'dispatched-*.json' | Sort-Object LastWriteTime -Descending | Select-Object -First 2 | ForEach-Object {
